const ensureCount = (items: string[], minimum: number, filler: string[]): string[] => {
  const next = [...new Set(items.filter(Boolean))];
  for (const f of filler) {
    if (next.length >= minimum) break;
    if (!next.includes(f)) next.push(f);
  }
  return next;
};

